exercises.solution_code:
#include <iostream>

int main()
{
    char ch{};
    std::cin >> ch;

    int code{ static_cast<int>(ch) };

    bool printable{ code >= 32 && code <= 126 };

    bool is_digit{ ch >= '0' && ch <= '9' };

    std::cout << std::boolalpha;
    std::cout << "Code: " << code << '\n';
    std::cout << "Printable: " << printable << '\n';
    std::cout << "Digit: " << is_digit << '\n';

    return 0;
}

